namespace Application.Services.Interface;

/// <summary>
/// Provides the authenticated user's profile and organizational positions.
/// </summary>
public interface IUserContextService
{
    /// <summary>
    /// Loads the current user's session profile and owned positions.
    /// </summary>
    Task<UserContextSnapshot> GetSnapshotAsync(CancellationToken cancellationToken);

    /// <summary>
    /// Returns true when the position belongs to the current user.
    /// </summary>
    Task<bool> OwnsPositionAsync(int positionId, CancellationToken cancellationToken);
}

/// <summary>
/// Snapshot of the current user for session bootstrap.
/// </summary>
public sealed class UserContextSnapshot
{
    public int UserId { get; init; }
    public string FullName { get; init; } = string.Empty;
    public string? AvatarUrl { get; init; }
    public bool IsActive { get; init; }
    public IReadOnlyList<UserPositionSnapshot> Positions { get; init; } = [];
    public int SelectedPositionId { get; init; }
}

/// <summary>
/// One organizational position owned by the current user.
/// </summary>
public sealed class UserPositionSnapshot
{
    public int Id { get; init; }
    public string Title { get; init; } = string.Empty;
    public bool IsDefault { get; init; }
    public IReadOnlyList<int> RoleIds { get; init; } = [];
}

namespace Application.Services.Interface;

/// <summary>
/// Resolves which form templates a user/position may access.
/// </summary>
public interface IFormAccessService
{
    /// <summary>
    /// Returns accessible active form template ids for the given user, position, and type.
    /// </summary>
    Task<IReadOnlyList<int>> GetAccessibleFormIdsAsync(
        int userId,
        int positionId,
        FormType type,
        CancellationToken cancellationToken);

    /// <summary>
    /// Returns whether the user may access the form in the given position context.
    /// </summary>
    Task<bool> CanAccessFormAsync(
        int userId,
        int positionId,
        int formId,
        CancellationToken cancellationToken);

    /// <summary>
    /// Counts accessible active templates for a type (used for hub tile visibility).
    /// </summary>
    Task<int> CountAccessibleAsync(
        int userId,
        int positionId,
        FormType type,
        CancellationToken cancellationToken);
}

