using Application.Services.Interface;
using Domain.Models;
using Domain.Models.Organization;
using Microsoft.EntityFrameworkCore;
using Serilog;

namespace Application.Services;

/// <summary>
/// Loads the current user's profile and owned positions only.
/// </summary>
public class UserContextService(
    IApplicationDbContext context,
    ICurrentUserService currentUserService,
    IOrgPositionService orgPositionService) : IUserContextService
{
    /// <inheritdoc />
    public async Task<UserContextSnapshot> GetSnapshotAsync(CancellationToken cancellationToken)
    {
        var userId = currentUserService.UserId();
        var user = await context.AppUsers
            .AsNoTracking()
            .FirstOrDefaultAsync(x => x.Id == userId, cancellationToken);

        if (user is null)
        {
            return new UserContextSnapshot
            {
                UserId = userId,
                IsActive = false,
                Positions = [],
                SelectedPositionId = 0
            };
        }

        var positions = await LoadOwnedPositionsAsync(userId, user.OrgPositionId, cancellationToken);
        var selected = positions.FirstOrDefault(x => x.IsDefault)?.Id
            ?? positions.FirstOrDefault()?.Id
            ?? 0;

        return new UserContextSnapshot
        {
            UserId = userId,
            FullName = user.Name,
            AvatarUrl = string.IsNullOrWhiteSpace(user.ProfileImage) ? null : user.ProfileImage,
            IsActive = user.IsActive,
            Positions = positions,
            SelectedPositionId = selected
        };
    }

    /// <inheritdoc />
    public async Task<bool> OwnsPositionAsync(int positionId, CancellationToken cancellationToken)
    {
        var snapshot = await GetSnapshotAsync(cancellationToken);
        return snapshot.Positions.Any(x => x.Id == positionId);
    }

    private async Task<IReadOnlyList<UserPositionSnapshot>> LoadOwnedPositionsAsync(
        int userId,
        int? legacyPositionId,
        CancellationToken cancellationToken)
    {
        try
        {
            var qOrg = await context.OrgPositions
                .Include(x => x.JobTitle)
                .Include(x => x.Project)
                .Include(x => x.ParentProject)
                .Include(x => x.Roles)
                .Include(x => x.Users)
                .AsNoTracking()
                .Where(x => x.IsDeleted == false)
                .ToListAsync(cancellationToken);

            qOrg = orgPositionService.RemoveInactiveProjects(qOrg);

            var junctionIds = qOrg
                .Where(p => p.Users.Any(u => u.UserId == userId))
                .Select(p => p.Id)
                .ToHashSet();

            if (legacyPositionId.HasValue)
                junctionIds.Add(legacyPositionId.Value);

            var owned = qOrg
                .Where(p => junctionIds.Contains(p.Id))
                .Select(p => new UserPositionSnapshot
                {
                    Id = p.Id,
                    Title = p.ParentProjectId.HasValue
                        ? $"[{p.ParentProject.Name}] {p.Title}"
                        : p.Title,
                    IsDefault = legacyPositionId.HasValue && p.Id == legacyPositionId.Value,
                    RoleIds = p.Roles.Select(r => r.RoleId).Distinct().ToList()
                })
                .OrderBy(p => p.Title)
                .ToList();

            if (owned.Count > 0 && owned.All(x => !x.IsDefault))
            {
                owned[0] = new UserPositionSnapshot
                {
                    Id = owned[0].Id,
                    Title = owned[0].Title,
                    IsDefault = true,
                    RoleIds = owned[0].RoleIds
                };
            }

            return owned;
        }
        catch (Exception ex)
        {
            Log.Error(ex, "UserContextService.LoadOwnedPositionsAsync");
            return [];
        }
    }
}

