namespace Application.Services;

/// <summary>
/// Resolves form template access from FormRole and FormTemplatePosition links.
/// </summary>
/// <remarks>
/// PermitNew listing uses the same ACL rows for hub menus; full workflow authorization
/// remains on FormData submit paths (FORMS_SYSTEM.md). Unrestricted templates
/// (no roles and no positions) are visible to any owned position.
/// </remarks>
public class FormAccessService(IApplicationDbContext context) : IFormAccessService
{
    /// <inheritdoc />
    public async Task<IReadOnlyList<int>> GetAccessibleFormIdsAsync(
        int userId,
        int positionId,
        FormType type,
        CancellationToken cancellationToken)
    {
        _ = userId;
        var roleIds = await context.PositionRoles
            .AsNoTracking()
            .Where(x => x.OrgPositionId == positionId)
            .Select(x => x.RoleId)
            .Distinct()
            .ToListAsync(cancellationToken);

        var forms = await context.FormTemplates
            .AsNoTracking()
            .Where(x => x.IsActive && x.Type == type)
            .Select(x => new
            {
                x.Id,
                RoleIds = x.Roles.Select(r => r.RoleId).ToList(),
                PositionIds = x.FormTemplatePositions.Select(p => p.PositionId).ToList()
            })
            .ToListAsync(cancellationToken);

        return forms
            .Where(f => IsAccessible(f.RoleIds, f.PositionIds, roleIds, positionId))
            .Select(f => f.Id)
            .ToList();
    }

    /// <inheritdoc />
    public async Task<bool> CanAccessFormAsync(
        int userId,
        int positionId,
        int formId,
        CancellationToken cancellationToken)
    {
        var form = await context.FormTemplates
            .AsNoTracking()
            .Where(x => x.Id == formId && x.IsActive)
            .Select(x => new
            {
                x.Type,
                RoleIds = x.Roles.Select(r => r.RoleId).ToList(),
                PositionIds = x.FormTemplatePositions.Select(p => p.PositionId).ToList()
            })
            .FirstOrDefaultAsync(cancellationToken);

        if (form is null)
            return false;

        var ids = await GetAccessibleFormIdsAsync(userId, positionId, form.Type, cancellationToken);
        return ids.Contains(formId);
    }

    /// <inheritdoc />
    public async Task<int> CountAccessibleAsync(
        int userId,
        int positionId,
        FormType type,
        CancellationToken cancellationToken)
    {
        var ids = await GetAccessibleFormIdsAsync(userId, positionId, type, cancellationToken);
        return ids.Count;
    }

    private static bool IsAccessible(
        IReadOnlyList<int> formRoleIds,
        IReadOnlyList<int> formPositionIds,
        IReadOnlyList<int> positionRoleIds,
        int positionId)
    {
        if (formRoleIds.Count == 0 && formPositionIds.Count == 0)
            return true;

        if (formRoleIds.Any(r => positionRoleIds.Contains(r)))
            return true;

        if (formPositionIds.Contains(positionId))
            return true;

        return false;
    }
}

namespace Application.Services;

/// <summary>
/// Builds the four Forms hub tiles from accessible form counts.
/// </summary>
public class WorkflowTileService(IFormAccessService formAccessService) : IWorkflowTileService
{
    private static readonly (FormType Type, string Title)[] HubTiles =
    [
        (FormType.Form, "فرم"),
        (FormType.CheckList, "چک لیست"),
        (FormType.PermitNew, "فرآیند"),
        (FormType.Emergency, "مسیر اقدام")
    ];

    /// <inheritdoc />
    public async Task<IReadOnlyList<WorkflowTileSnapshot>> GetTilesAsync(
        int userId,
        int positionId,
        CancellationToken cancellationToken)
    {
        var result = new List<WorkflowTileSnapshot>(HubTiles.Length);

        if (positionId <= 0)
        {
            foreach (var (type, title) in HubTiles)
            {
                result.Add(new WorkflowTileSnapshot
                {
                    Type = type,
                    Title = title,
                    Visible = false,
                    Badge = 0
                });
            }

            return result;
        }

        foreach (var (type, title) in HubTiles)
        {
            var count = await formAccessService.CountAccessibleAsync(
                userId, positionId, type, cancellationToken);

            result.Add(new WorkflowTileSnapshot
            {
                Type = type,
                Title = title,
                Visible = count > 0,
                Badge = 0
            });
        }

        return result;
    }
}

