/// <summary>
/// Session bootstrap payload for Forms hub chrome (not a dashboard).
/// </summary>
public record SessionBootstrapDto
{
    /// <summary>Gets or sets the current user profile.</summary>
    public SessionProfileDto Profile { get; set; } = new();

    /// <summary>Gets or sets positions owned by the current user only.</summary>
    public List<SessionPositionDto> Positions { get; set; } = [];

    /// <summary>Gets or sets the selected / default position id.</summary>
    public int SelectedPositionId { get; set; }

    /// <summary>Gets or sets light badge counts for navigation.</summary>
    public SessionBadgesDto Badges { get; set; } = new();

    /// <summary>Gets or sets the four Forms hub workflow tiles.</summary>
    public List<WorkflowTileDto> WorkflowTiles { get; set; } = [];

    /// <summary>Gets or sets bottom-navigation flags.</summary>
    public SessionNavigationDto Navigation { get; set; } = new();

    /// <summary>Gets or sets optional lite settings (not Sync/Setting bulk).</summary>
    public SettingsLiteDto? SettingsLite { get; set; }
}

