namespace Application.Features.Query;

/// <summary>
/// Query for light session bootstrap used by the Forms hub.
/// </summary>
public record GetSessionBootstrapQuery() : IRequest<Result<SessionBootstrapDto>>;

namespace Application.Features.Query;

/// <summary>
/// Handles <see cref="GetSessionBootstrapQuery"/> for Forms hub chrome.
/// </summary>
/// <remarks>
/// <strong>Execution Flow:</strong>
/// <list type="number">
/// <item>Loads profile and owned positions via <see cref="IUserContextService"/>.</item>
/// <item>Builds four workflow tiles via <see cref="IWorkflowTileService"/>.</item>
/// <item>Loads cheap badge counts (notifications, messages, tasks).</item>
/// <item>Returns navigation flags with default tab = forms.</item>
/// </list>
/// </remarks>
public class GetSessionBootstrapQueryHandler(
    IApplicationDbContext context,
    IUserContextService userContextService,
    IWorkflowTileService workflowTileService)
    : IRequestHandler<GetSessionBootstrapQuery, Result<SessionBootstrapDto>>
{
    /// <summary>
    /// Executes the session bootstrap query.
    /// </summary>
    /// <param name="request">The bootstrap query.</param>
    /// <param name="cancellationToken">Cancellation token.</param>
    /// <returns>Session bootstrap DTO on success; server error on failure.</returns>
    public async Task<Result<SessionBootstrapDto>> Handle(
        GetSessionBootstrapQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            var snapshot = await userContextService.GetSnapshotAsync(cancellationToken);
            if (!snapshot.IsActive && snapshot.UserId > 0 && string.IsNullOrWhiteSpace(snapshot.FullName))
                return FormHubErrors.UserInactive;

            var tiles = await workflowTileService.GetTilesAsync(
                snapshot.UserId,
                snapshot.SelectedPositionId,
                cancellationToken);

            var notificationsUnread = await context.NotificationItems
                .AsNoTracking()
                .Where(x => x.NotificationCenter.UserId == snapshot.UserId)
                .Where(x => !x.ReadDateTime.HasValue)
                .CountAsync(cancellationToken);

            var messagesUnread = await context.MessageRecipients
                .AsNoTracking()
                .Where(x => x.AppUserId == snapshot.UserId)
                .Where(x => !x.IsRead)
                .CountAsync(cancellationToken);

            var tasksPending = await context.TaskItems
                .AsNoTracking()
