                    })
                    .ToList(),
                SelectedPositionId = snapshot.SelectedPositionId,
                Badges = new SessionBadgesDto
                {
                    NotificationsUnread = notificationsUnread,
                    MessagesUnread = messagesUnread,
                    TasksPending = tasksPending
                },
                WorkflowTiles = tiles
                    .Select(t => new WorkflowTileDto
                    {
