/// <summary>
/// Validates <see cref="GetFormMenuQuery"/>.
/// </summary>
public class GetFormMenuQueryValidator : AbstractValidator<GetFormMenuQuery>
{
    private static readonly HashSet<string> AllowedTypes = new(StringComparer.OrdinalIgnoreCase)
    {
        nameof(FormType.Form),
        nameof(FormType.CheckList),
        nameof(FormType.PermitNew),
        nameof(FormType.Emergency)
    };

    public GetFormMenuQueryValidator()
    {
