            .GreaterThanOrEqualTo(0);

        RuleFor(x => x.PageSize)
            .InclusiveBetween(1, 100);
    }
}

namespace Application.Features.Query;

/// <summary>
/// Handles <see cref="GetFormMenuQuery"/> for type-scoped light form lists.
/// </summary>
/// <remarks>
/// <strong>Execution Flow:</strong>
/// <list type="number">
/// <item>Validates the position belongs to the current user.</item>
/// <item>Parses hub FormType (case-insensitive).</item>
/// <item>Resolves accessible ids via <see cref="IFormAccessService"/>.</item>
/// <item>Returns paginated light menu items without fields.</item>
/// </list>
/// </remarks>
public class GetFormMenuQueryHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUserService,
    IUserContextService userContextService,
    IFormAccessService formAccessService)
    : IRequestHandler<GetFormMenuQuery, Result<PaginatedResult<FormMenuItemDto>>>
{
    /// <summary>
    /// Executes the forms menu query.
    /// </summary>
    /// <param name="request">Menu query parameters.</param>
    /// <param name="cancellationToken">Cancellation token.</param>
    /// <returns>Paginated menu items on success.</returns>
    public async Task<Result<PaginatedResult<FormMenuItemDto>>> Handle(
        GetFormMenuQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            var userId = currentUserService.UserId();
            if (!await userContextService.OwnsPositionAsync(request.PositionId, cancellationToken))
                return FormHubErrors.PositionNotAllowed;

            if (!Enum.TryParse<FormType>(request.Type.Trim(), ignoreCase: true, out var formType)
                || formType is not (FormType.Form or FormType.CheckList or FormType.PermitNew or FormType.Emergency))
            {
                return FormHubErrors.InvalidHubType;
            }

            var accessibleIds = await formAccessService.GetAccessibleFormIdsAsync(
                userId, request.PositionId, formType, cancellationToken);

            var qBase = context.FormTemplates
                .AsNoTracking()
                .Where(x => x.IsActive && x.Type == formType)
                .Where(x => accessibleIds.Contains(x.Id));

            var totalCount = await qBase.CountAsync(cancellationToken);

            var pageIndex = request.PageIndex < 0 ? 0 : request.PageIndex;
            var pageSize = request.PageSize < 1 ? 20 : request.PageSize;

            var items = await qBase
                .OrderBy(x => x.NO)
                .ThenBy(x => x.Id)
                .Skip(pageIndex * pageSize)
                .Take(pageSize)
                .Select(x => new FormMenuItemDto
                {
                    Id = x.Id,
                    Name = x.Name,
                    Type = x.Type,
                    CategoryName = x.Category != null ? x.Category.Name : null,
                    Order = x.NO,
                    Code = string.IsNullOrWhiteSpace(x.Code) ? null : x.Code
                })
                .ToListAsync(cancellationToken);

            var result = new PaginatedResult<FormMenuItemDto>(
                items,
                pageIndex,
                pageSize,
                items.Count,
                totalCount);

            return Result<PaginatedResult<FormMenuItemDto>>.Success(result);
        }
        catch (Exception ex)
        {
            Log.Error(ex, "GetFormMenu");
            return Error.ServerError;
        }
    }
}

