namespace Application.Features.Query;

/// <summary>
/// Handles <see cref="GetFormTemplateDetailQuery"/> for a single accessible template.
/// </summary>
/// <remarks>
/// <strong>Execution Flow:</strong>
/// <list type="number">
/// <item>Validates the position belongs to the current user.</item>
/// <item>Loads the active template; returns NotFound when missing/inactive.</item>
/// <item>Checks access; returns AccessForbidden when denied.</item>
/// <item>Attaches active fields and maps to <see cref="FormTemplateDto"/>.</item>
/// </list>
/// </remarks>
public class GetFormTemplateDetailQueryHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUserService,
    IUserContextService userContextService,
    IFormAccessService formAccessService)
    : IRequestHandler<GetFormTemplateDetailQuery, Result<FormTemplateDto>>
{
    /// <summary>
    /// Executes the form template detail query.
    /// </summary>
    /// <param name="request">Detail query parameters.</param>
    /// <param name="cancellationToken">Cancellation token.</param>
    /// <returns>Form template DTO with active fields on success.</returns>
    public async Task<Result<FormTemplateDto>> Handle(
        GetFormTemplateDetailQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            var userId = currentUserService.UserId();
            if (!await userContextService.OwnsPositionAsync(request.PositionId, cancellationToken))
                return FormHubErrors.PositionNotAllowed;

            var form = await context.FormTemplates
                .AsNoTracking()
                .Include(x => x.Roles)
                .Include(x => x.FormTemplatePositions)
                .Include(x => x.Category)
                .FirstOrDefaultAsync(x => x.Id == request.Id, cancellationToken);

            if (form is null || !form.IsActive)
                return FormHubErrors.FormNotFound;

            var canAccess = await formAccessService.CanAccessFormAsync(
                userId, request.PositionId, request.Id, cancellationToken);
            if (!canAccess)
                return FormHubErrors.FormAccessDenied;

            var fields = await context.FormFields
                .AsNoTracking()
                .Where(x => x.FormId == form.Id && x.IsActive)
                .OrderBy(x => x.NO)
                .ToListAsync(cancellationToken);

            form.Fields = fields;

            var dto = form.Adapt<FormTemplateDto>();
            if (dto.LastRevisedDate < DateTime.Now.AddYears(-100))
                dto.LastRevisedDate = null;

            return Result<FormTemplateDto>.Success(dto);
        }
        catch (Exception ex)
        {
            Log.Error(ex, "GetFormTemplateDetail");
            return Error.ServerError;
        }
    }
}

