namespace Application.Features.Query;

/// <summary>
/// Handles <see cref="GetStatsSummaryQuery"/> with user-scoped aggregates.
/// </summary>
/// <remarks>
/// Mirrors dashboard count semantics without chart payloads. PositionId is ignored in v1.
/// </remarks>
public class GetStatsSummaryQueryHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUserService)
    : IRequestHandler<GetStatsSummaryQuery, Result<StatsSummaryDto>>
{
    /// <summary>
    /// Executes the stats summary query.
    /// </summary>
    /// <param name="request">Stats query (position optional).</param>
    /// <param name="cancellationToken">Cancellation token.</param>
    /// <returns>Stats summary DTO on success.</returns>
    public async Task<Result<StatsSummaryDto>> Handle(
        GetStatsSummaryQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            _ = request.PositionId;
            var userId = currentUserService.UserId();
            List<FormType> types = [FormType.Form, FormType.CheckList, FormType.Anomaly];
            var decisionFormActions = new[]
            {
                FormActionType.Approve,
                FormActionType.Reject,
            };

            var qFrom = await context.FormData
                .AsNoTracking()
                .Where(x => x.WorkflowSteps.First().UserId == userId)
                .Where(x => types.Contains(x.Form.Type))
                .Select(x => new
                {
                    x.Form.Type,
                    Actions = x.WorkflowSteps.Select(y => new { y.UserId, y.Type, y.ActionDate }).ToList()
                })
                .ToListAsync(cancellationToken);

            var qTask = await context.TaskItems
                .AsNoTracking()
                .Where(x => x.AssignedToUserId == userId)
                .Select(x => new { x.Status })
                .ToListAsync(cancellationToken);

            var dto = new StatsSummaryDto
            {
                AnomalyCount = qFrom.Count(x => x.Type == FormType.Anomaly),
                FormCount = qFrom.Count(x => x.Type is FormType.Form or FormType.CheckList),
                ApproveFormCount = qFrom
                    .Where(x => x.Type is FormType.Form or FormType.CheckList)
                    .Count(x => x.Actions
                        .Where(a => decisionFormActions.Contains(a.Type))
                        .OrderByDescending(a => a.ActionDate)
                        .FirstOrDefault()?.Type == FormActionType.Approve),
                RejectFormCount = qFrom
                    .Where(x => x.Type is FormType.Form or FormType.CheckList)
                    .Count(x => x.Actions
                        .Where(a => decisionFormActions.Contains(a.Type))
                        .OrderByDescending(a => a.ActionDate)
                        .FirstOrDefault()?.Type == FormActionType.Reject),
                TaskCount = qTask.Count,
                DoneTaskCount = qTask.Count(x => x.Status == Domain.Enums.TaskStatus.Approved),
                MessageCount = await context.MessageRecipients
                    .AsNoTracking()
                    .Where(x => x.AppUserId == userId)
                    .Where(x => !x.IsRead)
                    .CountAsync(cancellationToken),
                NotificationCount = await context.NotificationItems
                    .AsNoTracking()
                    .Where(x => x.NotificationCenter.UserId == userId)
                    .Where(x => !x.ReadDateTime.HasValue)
                    .CountAsync(cancellationToken)
            };

            return Result<StatsSummaryDto>.Success(dto);
        }
        catch (Exception ex)
        {
            Log.Error(ex, "GetStatsSummary");
            return Error.ServerError;
        }
    }
}

