/// <summary>
/// Endpoint for session bootstrap used by the Forms hub.
/// </summary>
public class SessionBootstrapEndPoint : ICarterModule
{
    /// <summary>
    /// Registers the GET /session/bootstrap route.
    /// </summary>
    /// <param name="app">The endpoint route builder.</param>
    /// <remarks>
    /// <strong>Execution Flow:</strong>
    /// <list type="number">
    /// <item>Listens for GET /session/bootstrap.</item>
    /// <item>Sends <see cref="GetSessionBootstrapQuery"/> via MediatR.</item>
    /// <item>Returns 200 OK with session chrome, or Problem on failure.</item>
    /// </list>
    /// </remarks>
    public void AddRoutes(IEndpointRouteBuilder app)
    {
        app.MapGet("/session/bootstrap", async (ISender sender) =>
        {
            var res = await sender.Send(new GetSessionBootstrapQuery());
            if (res.IsSuccess)
                return Results.Ok(res.Value);

            var status = MapStatus(res.Error!.ErrorType);
            return Results.Problem(res.Error.Description, statusCode: status);
        })
        .WithName("SessionBootstrap")
        .Produces<SessionBootstrapDto>(StatusCodes.Status200OK)
        .ProducesProblem(StatusCodes.Status400BadRequest)
        .ProducesProblem(StatusCodes.Status401Unauthorized)
        .ProducesProblem(StatusCodes.Status403Forbidden)
        .WithSummary("SessionBootstrap")
        .WithDescription("Returns Forms hub chrome: profile, my positions, tiles, badges. Not a dashboard.")
        .RequireRateLimiting(RateLimitConst.RateFix)
        .RequireAuthorization();
    }

    private static int MapStatus(ErrorType type) => type switch
    {
        ErrorType.UnauthorizedAccess => StatusCodes.Status401Unauthorized,
        ErrorType.AccessForbidden => StatusCodes.Status403Forbidden,
        ErrorType.NotFound => StatusCodes.Status404NotFound,
        ErrorType.Validation => StatusCodes.Status400BadRequest,
        _ => StatusCodes.Status400BadRequest
    };
}

