using Api.Constants;
using Application.Features.Query;
using ElayAdmin.Api.Application.Features.Query;

namespace Api.EndPoint.Sync;

/// <summary>
/// Endpoint for synchronizing various application settings and data (users, positions, projects, etc.).
/// </summary>
public class SyncEndPoint : ICarterModule
{
    /// <summary>
    /// Represents a synchronization request.
    /// </summary>
    public record Request();

    /// <summary>
    /// Configures the routes for settings synchronization.
    /// </summary>
    /// <param name="app">The endpoint route builder.</param>
    public void AddRoutes(IEndpointRouteBuilder app)
    {
        app.MapGet("/Sync/Setting", async (ISender sender
            , ICurrentUserService currentUser
            , HttpResponse httpResponse) =>
        {
            // Deprecated for new mobile login path — prefer /session/bootstrap
            httpResponse.Headers.Append("Deprecation", "true");
            httpResponse.Headers.Append("X-Elay-Deprecated-For", "mobile-login");
            httpResponse.Headers.Append("X-Elay-Successor", "/session/bootstrap");
            Log.Warning("Deprecated endpoint hit: GET /Sync/Setting (userId={UserId})", currentUser.UserId());

            SettingQuery querySetting = new SettingQuery();
            var resSetting = await sender.Send(querySetting);
            if (!resSetting.IsSuccess)
                return Results.Problem(resSetting!.Error!.Description, statusCode: 400);

            GetUserQuery queryUser = new GetUserQuery();
            var resUser = await sender.Send(queryUser);
            if (!resUser.IsSuccess)
                return Results.Problem(resUser!.Error!.Description, statusCode: 400);

            GetAllPositionsQuery queryPosition = new GetAllPositionsQuery();
            var resPosition = await sender.Send(queryPosition);
            if (!resPosition.IsSuccess)
                return Results.Problem(resPosition!.Error!.Description, statusCode: 400);

            GetAllProjectsDtoQuery queryProject = new GetAllProjectsDtoQuery();
            var resProject = await sender.Send(queryProject);
            if (!resProject.IsSuccess)
                return Results.Problem(resProject!.Error!.Description, statusCode: 400);

            GetAllJobTitlesDtoQuery queryJob = new GetAllJobTitlesDtoQuery();
            var resJob = await sender.Send(queryJob);
            if (!resJob.IsSuccess)
                return Results.Problem(resJob!.Error!.Description, statusCode: 400);

            var setting = new AllSettingDto(resSetting.Value.Result
                , resUser.Value.Result
                , resPosition.Value.Result
                , resProject.Value.Result,
                resJob.Value.Result
                );

            if (resSetting.IsSuccess)
                return Results.Ok(setting);

            return Results.Problem(resSetting!.Error!.Description, statusCode: 400);

        }).WithName("syncSetting")
        .Produces<SettingDto>(StatusCodes.Status200OK)
        .ProducesProblem(StatusCodes.Status400BadRequest)
        .WithSummary("syncSetting (deprecated for mobile login)")
        .WithDescription("Bulk settings sync (all users/positions). Deprecated for new mobile login path; use /session/bootstrap.")
            .RequireRateLimiting(RateLimitConst.RateFix)
            .RequireAuthorization()
            ;
    }
}

