// Seed ChatTest users onto organizational positions for Forms Hub Stage 2 Postman.
// Prefer API when available; here we use the approved CreateChatTestUsers EF path.

var config = new ConfigurationBuilder()
    .SetBasePath(@"d:\Elay_Backend-master\Customer\Api")
    .AddJsonFile("appsettings.json", optional: false)
    .AddJsonFile("appsettings.Development.json", optional: true)
    .Build();

var services = new ServiceCollection();
services.AddSingleton<IConfiguration>(config);
services.AddInfrastructureServices(config);
services.AddSingleton<ISecurityService, SecurityService>();
services.AddSingleton<ICurrentUserService, SetupCurrentUserService>();
services.AddSingleton<IDateTimeService, DateTimeService>();

var sp = services.BuildServiceProvider();
using var scope = sp.CreateScope();
