var usernames = new[] { "chattest_sara", "chattest_reza", "chattest_nima", "chattest_kian" };
var users = await context.AppUsers
    .Where(u => usernames.Contains(u.Username))
    .ToListAsync();

if (users.Count == 0)
{
    Console.WriteLine("ERROR: ChatTest users not found. Run CreateChatTestUsers first.");
    return;
}

foreach (var u in users)
    Console.WriteLine($"USER {u.Username} id={u.Id} OrgPositionId={u.OrgPositionId}");

// Prefer existing active positions that already have users (stable org nodes).
var candidateIds = await context.OrgPositions
    .AsNoTracking()
    .Where(p => !p.IsDeleted)
    .Where(p => p.Users.Any())
    .OrderBy(p => p.Id)
    .Select(p => p.Id)
    .Take(20)
    .ToListAsync();

if (candidateIds.Count < 2)
{
