function Record([string]$id, [bool]$ok, [string]$detail) {
  $results.Add([pscustomobject]@{ Id = $id; Ok = $ok; Detail = $detail })
  $mark = if ($ok) { 'PASS' } else { 'FAIL' }
  Write-Host "[$mark] $id — $detail"
}

function Login([string]$username, [string]$password = 'Test@12345') {
  $body = @{ username = $username; password = $password; deviceInfo = $device } | ConvertTo-Json -Depth 5
  return Invoke-RestMethod -Uri "$baseUrl/Auth/Login" -Method POST -ContentType 'application/json' -Body $body
}

function Invoke-Api([string]$method, [string]$path, $headers = $null, $body = $null, [switch]$Raw) {
  $uri = "$baseUrl$path"
  $params = @{ Uri = $uri; Method = $method; SkipHttpErrorCheck = $true }
  if ($headers) { $params.Headers = $headers }
  if ($body) {
    $params.ContentType = 'application/json'
    $params.Body = if ($body -is [string]) { $body } else { $body | ConvertTo-Json -Depth 8 }
  }
  $resp = Invoke-WebRequest @params
  if ($Raw) { return $resp }
  $json = $null
  if ($resp.Content) {
    try { $json = $resp.Content | ConvertFrom-Json } catch { $json = $resp.Content }
  }
  return [pscustomobject]@{ StatusCode = [int]$resp.StatusCode; Headers = $resp.Headers; Body = $json; Raw = $resp.Content }
}

